def generate_password_hash(password):
    salt = sha256(os.urandom(256)).digest()
    pwdhash = base64.b64encode(salt + sha256(password.encode('utf-8')).digest())
    return pwdhash

def verify_password_hash(password, hash):
    salt = base64.b64decode(hash)[:32]
    password_hash = base64.b64decode(hash)[32:]
    if sha256(password.encode('utf-8') + salt).digest() == password_hash:
        return True
    return False

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    if not data or 'password' not in data:
        return jsonify({"message": "Missing data"}), 400

    password = generate_password_hash(data['password'])
    user = {'id': 1, 'password': password}
    return jsonify({"message": "User created", "user": user}), 201

